        max(case when question_code = 'question_119' then coalesce(cast(response_int as text), response_text) end) as "I am clear about the process of finding / pursuing my purpose in life",
        max(case when question_code = 'question_120' then coalesce(cast(response_int as text), response_text) end) as "I understand the need, importance and unique roles of the social sector in society",
        max(case when question_code = 'question_121' then coalesce(cast(response_int as text), response_text) end) as "I exhibit the courage to live authentically with my values and beliefs even if they are against conventional norms",
        max(case when question_code in ('question_122', 'question_128') then coalesce(cast(response_int as text), response_text) end) as "I understand the difference between 'social work activities' and 'social problem-solving approach'",
        max(case when question_code = 'question_123' then coalesce(cast(response_int as text), response_text) end) as "I have given a careful thought to what I want to do in my life",
        max(case when question_code = 'question_124' then coalesce(cast(response_int as text), response_text) end) as "My choice of what I want to do in my life is not majorly influenced by the norms followed by my peers, seniors, society",
        max(case when question_code = 'question_125' then coalesce(cast(response_int as text), response_text) end) as "I know the difference between my 'financial needs' and my 'aspirational income'",
        max(case when question_code in ('question_126', 'question_130') then coalesce(cast(response_int as text), response_text) end) as "I can visualise various possible ways in which I can contribute in the social sector (v2)",

        -- NEW: Batch .3 questions (q127+) — genuinely new questions
        max(case when question_code = 'question_127' then coalesce(cast(response_int as text), response_text) end) as "Although most people wish to join pvt. or govt. sector, I can visualize myself pursuing a career in the social sector",
        max(case when question_code = 'question_129' then coalesce(cast(response_int as text), response_text) end) as "The elevation I feel when I see or read about other people devoting their lives for a social mission, strongly motivates me to act for social change",
